-- Create "process_instances" table
CREATE TABLE "process_instances" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "process_key" character varying NOT NULL,
  "process_version" character varying NOT NULL,
  "variant_key" character varying NULL,
  "config_revision" character varying NOT NULL,
  "definition_hash" character varying NOT NULL,
  "module_contract_snapshot" jsonb NULL,
  "business_ref_type" character varying NOT NULL,
  "business_ref_id" bigint NOT NULL,
  "business_ref_no" character varying NULL,
  "correlation_key" character varying NULL,
  "idempotency_key" character varying NOT NULL,
  "status" character varying NOT NULL DEFAULT 'active',
  "started_at" timestamptz NOT NULL,
  "completed_at" timestamptz NULL,
  "created_by" bigint NULL,
  "updated_by" bigint NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "processinstance_business_ref_type_business_ref_id" to table: "process_instances"
CREATE INDEX "processinstance_business_ref_type_business_ref_id" ON "process_instances" ("business_ref_type", "business_ref_id");
-- Create index "processinstance_config_revision_process_key" to table: "process_instances"
CREATE INDEX "processinstance_config_revision_process_key" ON "process_instances" ("config_revision", "process_key");
-- Create index "processinstance_correlation_key" to table: "process_instances"
CREATE INDEX "processinstance_correlation_key" ON "process_instances" ("correlation_key");
-- Create index "processinstance_process_key_business_ref_type_business_ref_id_i" to table: "process_instances"
CREATE UNIQUE INDEX "processinstance_process_key_business_ref_type_business_ref_id_i" ON "process_instances" ("process_key", "business_ref_type", "business_ref_id", "idempotency_key");
-- Create index "processinstance_status_updated_at" to table: "process_instances"
CREATE INDEX "processinstance_status_updated_at" ON "process_instances" ("status", "updated_at");
-- Create "process_node_instances" table
CREATE TABLE "process_node_instances" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "node_key" character varying NOT NULL,
  "node_type" character varying NOT NULL,
  "attempt" bigint NOT NULL DEFAULT 1,
  "status" character varying NOT NULL DEFAULT 'waiting',
  "owner_pool_key" character varying NULL,
  "required_capability_key" character varying NULL,
  "form_profile_key" character varying NULL,
  "action_set_key" character varying NULL,
  "policy_snapshot" jsonb NULL,
  "due_at" timestamptz NULL,
  "started_at" timestamptz NULL,
  "completed_at" timestamptz NULL,
  "outcome" character varying NULL,
  "version" bigint NOT NULL DEFAULT 1,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "process_instance_id" bigint NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "process_node_instances_process_instances_nodes" FOREIGN KEY ("process_instance_id") REFERENCES "process_instances" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION
);
-- Create index "processnodeinstance_due_at" to table: "process_node_instances"
CREATE INDEX "processnodeinstance_due_at" ON "process_node_instances" ("due_at");
-- Create index "processnodeinstance_owner_pool_key_status" to table: "process_node_instances"
CREATE INDEX "processnodeinstance_owner_pool_key_status" ON "process_node_instances" ("owner_pool_key", "status");
-- Create index "processnodeinstance_process_instance_id_node_key_attempt" to table: "process_node_instances"
CREATE UNIQUE INDEX "processnodeinstance_process_instance_id_node_key_attempt" ON "process_node_instances" ("process_instance_id", "node_key", "attempt");
-- Create index "processnodeinstance_process_instance_id_status" to table: "process_node_instances"
CREATE INDEX "processnodeinstance_process_instance_id_status" ON "process_node_instances" ("process_instance_id", "status");
-- Create index "processnodeinstance_required_capability_key_status" to table: "process_node_instances"
CREATE INDEX "processnodeinstance_required_capability_key_status" ON "process_node_instances" ("required_capability_key", "status");
